-USE_GMAKE=		yes
+USES+=			gmake
 MAKE_ENV+=		XERCESCROOT=${WRKSRC}

 HAS_CONFIGURE=		yes
@@ -172,16 +173,16 @@ post-configure:

 post-install:
 .if ${PORT_OPTIONS:MDOCS}
-	@${MKDIR} ${DOCSDIR}
-	@${CP} -r ${WRKSRC}/doc/ ${DOCSDIR}
+	@${MKDIR} ${STAGEDIR}${DOCSDIR}
+	@${CP} -r ${WRKSRC}/doc/ ${STAGEDIR}${DOCSDIR}
 .endif
 .if ${PORT_OPTIONS:MEXAMPLES}
-	@${MKDIR} ${EXAMPLESDIR}
